// Function to get the current count of consent items
export default function getCurrentConsentCount() {
  const consentItems = document.getElementById("consentList").querySelectorAll(".consent-item");

  if (consentItems.length > 0) {
    // Get the last element of the consent-item list
    const lastConsentItem = consentItems[consentItems.length - 1];
    // Retrieve the value from the 'data-last-item' attribute
    return parseInt(lastConsentItem.getAttribute("data-consent-id"));
  } else {
    // If there are no consent items, return 0
    return 0;
  }
}
