export function updateButtonStyles(target, buttonWrapperRightSide) {
  const value = target.value;
  const iziBackgroundSelectValue = document.querySelector("#inpostpayadmin #izi-background-select")?.value;
  const iziVariantSelectValue = document.querySelector("#inpostpayadmin #izi-variant-select")?.value;
  const iziFrameStyleSelectValue = document.querySelector("#inpostpayadmin #izi-frame-style-select")?.value;
  const iziSizeSelectValue = document.querySelector("#inpostpayadmin #izi_widget_v2_size")?.value;
  const iziButton = buttonWrapperRightSide.querySelector("inpost-izi-button");
  const iziButtonRoot = iziButton && iziButton.shadowRoot;
  const iziButtonShadowRoot = iziButtonRoot.querySelector(".inpostpay-widget");

  const sizeClasses = Array.from(iziButtonShadowRoot.classList).filter(className => className.startsWith('size-'));
  sizeClasses.forEach(className => iziButtonShadowRoot.classList.remove(className));
  iziButtonShadowRoot.classList.remove("rounded");
  iziButtonShadowRoot.classList.remove("round");
  iziButtonShadowRoot.classList.remove("none");
  iziButtonShadowRoot.classList.remove("dark");
  iziButtonShadowRoot.classList.remove("primary");
  iziButtonShadowRoot.classList.remove("secondary");

  iziButtonShadowRoot.classList.add(iziFrameStyleSelectValue);
  iziButtonShadowRoot.classList.add(iziSizeSelectValue);

  if (iziBackgroundSelectValue == "dark") {
    iziButtonShadowRoot.classList.add("dark");
    iziButtonShadowRoot.classList.remove("bright");
  } else {
    iziButtonShadowRoot.classList.remove("dark");
    iziButtonShadowRoot.classList.add("bright");
  }

  if (iziVariantSelectValue == "primary" || value == "primary") {
    iziButtonShadowRoot.classList.add("primary");
    iziButtonShadowRoot.classList.remove("secondary");
  } else {
    iziButtonShadowRoot.classList.add("secondary");
    iziButtonShadowRoot.classList.remove("primary");
  }
}
