// Add additional consent link from the template
import checkAdditionalLinksCount from "./checkAdditionalLinksCount";

export default function addAdditionalLink(consentId) {
  const additionalLinksDiv = document.getElementById(
    `additionalLinks${consentId}`
  );
  const template = document.getElementById("additionalLinkTemplate").innerHTML;
  let lastKey = parseInt(additionalLinksDiv.getAttribute('data-last-key'));
  lastKey++;

  // Create a new additional consent link from the template
  const tempDiv = document.createElement("div");
  tempDiv.innerHTML = template;
  const additionalLink = tempDiv.firstElementChild;

  const additionalLinkType = additionalLink.querySelector(".additional-consent-link");
  additionalLinkType.name = `izi_consents[${consentId}][additional_consent_links][${lastKey}][url]`;

  const additionalLinkIdentifier = additionalLink.querySelector(".additional-link-identifier");
  additionalLinkIdentifier.name = `izi_consents[${consentId}][additional_consent_links][${lastKey}][id]`;

  const additionalLinkLabel = additionalLink.querySelector(".additional-link-label");
  additionalLinkLabel.name = `izi_consents[${consentId}][additional_consent_links][${lastKey}][label]`;

  // Append the new additional consent link to the additional links div
  additionalLinksDiv.appendChild(additionalLink);

  checkAdditionalLinksCount(additionalLinksDiv);
  additionalLinksDiv.setAttribute('data-last-key', lastKey);

  // Add event listener for the remove button
  const removeBtn = additionalLink.querySelector(".remove-additional-link-btn");
  removeBtn.addEventListener("click", function () {
    additionalLink.remove();
    checkAdditionalLinksCount(additionalLinksDiv);
  });
}
