export default function disabledFields() {
  const relatedFields = [
    ["izi_shipping_price_cod_courier", "izi_shipping_method_cod_courier"],
    ["izi_shipping_price_pww_apm", "izi_shipping_method_pww_apm"],
    ["izi_shipping_price_cod_apm", "izi_shipping_method_cod_apm"],
  ];

  relatedFields.forEach(([pricePrefix, methodPrefix]) => {
    document.querySelectorAll(`select[name^='${methodPrefix}']`).forEach(selectElement => {
      const zoneId = selectElement.name.substring(methodPrefix.length);
      const priceName = pricePrefix + zoneId;
      const priceInput = document.querySelector(`input[name='${priceName}']`);

      if (priceInput) {
        priceInput.disabled = !selectElement.value;

        selectElement.addEventListener("change", () => {
          priceInput.disabled = !selectElement.value;
        });
      }
    });
  });
}
