import $ from 'jquery';
import select2 from 'select2';
import {createIziButton} from "./admin-script/createIziButton.js";
import {updateButtonStyles} from "./admin-script/updateButtonStyles.js";
import addConsentItem from "./admin-script/addConsentItem.js";
import addAdditionalLink from "./admin-script/addAdditionalLink.js";
import removeConsentItem from "./admin-script/removeConsentItem.js";
import removeAdditionalLink from "./admin-script/removeAdditionalLink.js";
import checkAdditionalLinksCount from "./admin-script/checkAdditionalLinksCount";
import validateForm from './admin-script/validateForm.js';
import disabledFields from "./admin-script/disabledFields";
import transportTab from './admin-script/transportTab.js';

$(document).ready(function () {
  $('#izi_payment_methods').select2();
});

document.addEventListener("DOMContentLoaded", function () {
  const inpostpayAdmin = document.querySelector("#inpostpayadmin");

  if (!inpostpayAdmin) {
    return;
  }

  validateForm();
  window.addConsentItem = addConsentItem;
  window.addAdditionalLink = addAdditionalLink;
  window.removeConsentItem = removeConsentItem;
  window.removeAdditionalLink = removeAdditionalLink;
  window.checkAdditionalLinksCount = checkAdditionalLinksCount;

  disabledFields();
  transportTab();

  const tooltips = document.querySelectorAll("#inpostpayadmin .input-tooltip-wrapper");
  const inpostpayTabContent = document.querySelector("#inpostpayadmin .tab-content");
  const inpostpayTabs = document.querySelectorAll("#inpostpayadmin .nav-tab");
  const iziBackgroundSelect = document.querySelector("#inpostpayadmin #izi-background-select");
  const iziVariantSelect = document.querySelector("#inpostpayadmin #izi-variant-select");
  const iziFrameStyleSelect = document.querySelector("#inpostpayadmin #izi-frame-style-select");
  const iziSizeSelect = document.querySelector("#inpostpayadmin #izi_widget_v2_size");
  const buttonWrapperRightSide = document.querySelector("#inpostpayadmin .button-wrapper-right-side");
  const iziVariantSelectValue = iziVariantSelect?.value;
  const iziBackgroundSelectValue = iziBackgroundSelect?.value;
  const iziFrameStyleSelectValue = iziFrameStyleSelect?.value;
  const iziSizeSelectValue = iziSizeSelect?.value;

  if (iziBackgroundSelectValue && iziVariantSelectValue && buttonWrapperRightSide) {
    const button = createIziButton(iziVariantSelectValue, iziBackgroundSelectValue, iziFrameStyleSelectValue, iziSizeSelectValue);
    buttonWrapperRightSide.innerHTML = button;
  }

  const changeEventCallback = (e) => updateButtonStyles(e.target, buttonWrapperRightSide);

  iziFrameStyleSelect && iziFrameStyleSelect.addEventListener("change", changeEventCallback);
  iziBackgroundSelect && iziBackgroundSelect.addEventListener("change", changeEventCallback);
  iziVariantSelect && iziVariantSelect.addEventListener("change", changeEventCallback);
  iziSizeSelect && iziSizeSelect.addEventListener("change", changeEventCallback);

  inpostpayTabs.forEach((tab) => {
    tab.addEventListener("click", (e) => {
      e.preventDefault();
      const target = e.target;
      const tabId = target.dataset.tabId;
      const activeTab = document.querySelector("#inpostpayadmin .nav-tab.nav-tab-active");
      const tabContent = document.querySelector(`#inpostpayadmin .tab-content[data-tab-id="${tabId}"]`);
      const activeTabContent = document.querySelector("#inpostpayadmin .tab-content:not(.tab-content-hidden)");

      if (target.classList.contains("nav-tab-active")) {
        return;
      }

      activeTab.classList.remove("nav-tab-active");
      target.classList.add("nav-tab-active");
      tabContent.classList.remove("tab-content-hidden");
      activeTabContent.classList.add("tab-content-hidden");
    });
  });

  inpostpayTabContent &&
  inpostpayTabContent.addEventListener("click", (e) => {
    const target = e.target;
    const tooltip = target.closest(".input-tooltip-wrapper");

    if (tooltip && tooltip.classList.contains("input-tooltip-wrapper-active")) {
      tooltip?.classList.remove("input-tooltip-wrapper-active");
    } else {
      tooltip?.classList.add("input-tooltip-wrapper-active");
    }

    tooltips.forEach((tooltipbox) => {
      if (tooltipbox !== tooltip) {
        tooltipbox.classList.remove("input-tooltip-wrapper-active");
      }
    });
  });

  if (window.location.hash) {
    const el = document.querySelector(window.location.hash);
    if (el) {
      el.scrollIntoView({behavior: 'smooth', block: 'center'});
      el.classList.add('izi-highlight');
      setTimeout(() => el.classList.remove('izi-highlight'), 4000);
    }
  }
});
