export default function validateForm() {
  const form = document.querySelector("#inpostpayadmin form");

  function addInputListeners(input) {
    ['input', 'change'].forEach(eventType => {
      input.addEventListener(eventType, validateInputs);
    });
  }

  function addSelectListeners(select) {
    ['change'].forEach(eventType => {
      select.addEventListener(eventType, validateSelects);
    });
  }

  document.querySelectorAll('.additional-link-identifier')
    .forEach(addInputListeners);

  document.querySelectorAll('.additional-consent-link')
    .forEach(addSelectListeners);

  const observer = new MutationObserver((mutations) => {
    mutations.forEach((mutation) => {
      mutation.addedNodes.forEach((node) => {
        if (node.nodeType === 1) {
          if (node.classList?.contains('additional-link-identifier')) {
            addInputListeners(node);
          }
          if (node.classList?.contains('additional-consent-link')) {
            addSelectListeners(node);
          }
          node.querySelectorAll('.additional-link-identifier')
            .forEach(addInputListeners);
          node.querySelectorAll('.additional-consent-link')
            .forEach(addSelectListeners);
        }
      });
    });
  });

  observer.observe(form, {
    childList: true,
    subtree: true
  });

  form.addEventListener("submit", function(e) {
    const isValidInputs = validateInputs();
    const isValidSelects = validateSelects();
    if (!isValidInputs || !isValidSelects) {
      const tabWithError = findTabIdOfFirstError();
      if (tabWithError) {
        const tabButton = document.querySelector(`button[data-tab-id="${tabWithError}"]`);
        const tabLabel = tabButton ? tabButton.textContent.trim() : tabWithError;

        const globalError = document.querySelector("#required-fields-global-error");
        if (globalError) {
          const errorMessageTemplate = globalError.dataset.templateMessage;
          const finalMessage = errorMessageTemplate.replace("%s", tabLabel);
          globalError.innerHTML = `<p>${finalMessage}</p>`;
          globalError.classList.remove("hidden");
          globalError.scrollIntoView({ behavior: "smooth", block: "center" });
        }
      }

      e.preventDefault();
      const errors = document.querySelectorAll(".duplicate-error");
      const lastError = errors[errors.length - 1];
      if (lastError) {
        lastError.scrollIntoView({ behavior: "smooth", block: "center" });
      }
    } else {
      form?.submit();
    }
  });
}

function removePreviousErrors(selector) {
  document.querySelectorAll(selector).forEach((select) => {
    const errorDiv = select.nextElementSibling;
    if (errorDiv && errorDiv.classList.contains("duplicate-error")) {
      errorDiv.remove();
    }
  });
}

function findTabIdOfFirstError() {
  const firstErrorInput = document.querySelector(".form-error, .duplicate-error");
  if (!firstErrorInput) return null;

  let parent = firstErrorInput;
  while (parent && parent !== document.body) {
    if (parent.dataset.tabId) {
      return parent.dataset.tabId;
    }
    parent = parent.parentElement;
  }

  return null;
}

function removeErrorClasses(inputs) {
  inputs.forEach(input => input.classList.remove("error"));
}

function getValidValues(inputs) {
  return Array.from(inputs)
    .map(input => input.value.trim())
    .filter(value => value !== '');
}

function findDuplicates(values) {
  return values.filter((value, index) => values.indexOf(value) !== index);
}

function showError(input, errorMessage) {
  const errorDiv = document.createElement("div");
  errorDiv.className = "duplicate-error";
  errorDiv.textContent = errorMessage;
  errorDiv.style.color = "red";
  input.parentNode.insertBefore(errorDiv, input.nextSibling);
  input.classList.add("error");
}

function markDuplicates(inputs, duplicates) {
  const duplicateValidationMessage = document.querySelector('[data-duplicate-validation-message]').dataset.duplicateValidationMessage;
  inputs.forEach((input) => {
    const trimmedValue = input.value.trim();
    if (duplicates.includes(trimmedValue)) {
      showError(input, duplicateValidationMessage);
    }
  });
}

function validateInputs() {
  const requiredValidationMessage = document.querySelector('[data-required-validation-message]').dataset.requiredValidationMessage;
  removePreviousErrors('input');

  const classesToValidate = ["additional-link-identifier"];
  let isValid = true;

  classesToValidate.forEach((className) => {
    const inputs = document.querySelectorAll(`.${className}:not(#additionalLinkTemplate .${className}):not(#consentTemplate *)`);

    if (inputs.length === 0) {
      return;
    }

    removeErrorClasses(inputs);

    inputs.forEach(input => {
      const value = input.value.trim();
      if (!value) {
        isValid = false;
        showError(input, requiredValidationMessage);
      }
    });

    if (isValid) {
      const values = getValidValues(inputs);
      const duplicates = findDuplicates(values);

      if (duplicates.length > 0) {
        isValid = false;
        markDuplicates(inputs, duplicates);
      }
    }
  });

  return isValid;
}

function validateSelects() {
  const requiredValidationMessage = document.querySelector('[data-required-validation-message]').dataset.requiredValidationMessage;
  removePreviousErrors('select');

  let isValid = true;
  const selectClassesToValidate = ["additional-consent-link"];

  selectClassesToValidate.forEach((className) => {
    const selects = document.querySelectorAll(`.${className}:not(#additionalLinkTemplate .${className}):not(#consentTemplate *)`);

    if (selects.length === 0) {
      return;
    }

    removeErrorClasses(selects);

    selects.forEach(select => {
      const value = select.value.trim();
      if (!value || value === "0") {
        isValid = false;
        showError(select, requiredValidationMessage);
      }
    });
  });

  return isValid;
}
