import getCurrentConsentCount from "./getCurrentConsentCount";
import checkConsentCount from "./checkConsentCount";

// Add new consent item from the template
export default function addConsentItem() {
  let consentCount = getCurrentConsentCount() + 1;

  const consentList = document.getElementById("consentList");
  const template = document.getElementById("consentTemplate").innerHTML;

  // Create a new consent item from the template
  const tempDiv = document.createElement("div");
  tempDiv.innerHTML = template;
  const consentDiv = tempDiv.firstElementChild;

  // Set the data-consent-id attribute for the new consent item
  consentDiv.setAttribute("data-consent-id", consentCount);

  // Update dynamic fields with unique IDs and names
  const consentLink = consentDiv.querySelector(".consentLink");
  consentLink.name = `izi_consents[${consentCount}][url]`;
  consentLink.id = `consentLink${consentCount}`;

  const additionalLinks = consentDiv.querySelector(".additional-links-container");
  additionalLinks.id = `additionalLinks${consentCount}`;

  const addAdditionalLinkBtn = consentDiv.querySelector(
    ".add-additional-link-btn"
  );
  addAdditionalLinkBtn.setAttribute(
    "onclick",
    `addAdditionalLink(${consentCount})`
  );

  const consentDescription = consentDiv.querySelector(".consentDescription");
  consentDescription.name = `izi_consents[${consentCount}][text]`;
  consentDescription.id = `consentDescription${consentCount}`;

  const requirementType = consentDiv.querySelector(".requirementType");
  requirementType.name = `izi_consents[${consentCount}][required]`;
  requirementType.id = `requirementType${consentCount}`;

  // Update indexes
  const listOfAdditionalLinks = consentDiv.querySelectorAll(".additional-link-container");
  listOfAdditionalLinks.forEach((link, subIndex) => {
    link.querySelectorAll("input, select").forEach((field) => {
      if (field.getAttribute("name") === '') {
        const fieldType = field.classList.contains("additional-link-identifier") ? "id" :
          field.classList.contains("additional-link-label") ? "label" :
            field.classList.contains("additional-consent-link") ? "url" : null;

        if (fieldType) {
          field.name = `izi_consents[${consentCount}][additional_consent_links][${subIndex}][${fieldType}]`;
        }
      }
    });
  });

  // Add event listener for removing the item
  consentDiv
    .querySelector(".remove-btn")
    .addEventListener("click", function () {
      consentDiv.remove();
      checkConsentCount();
    });

  // Append the new consent item to the list
  consentList.appendChild(consentDiv);

  // Check and update the Add Consent button visibility after adding a new item
  checkConsentCount();
}
