// Function to check the number of consent items and toggle the Add Consent button
export default function checkConsentCount() {
  const consentItems = document.getElementById("consentList").querySelectorAll(".consent-item").length;
  const addConsentBtn = document.getElementById("addConsentButton");

  if (consentItems >= 10) {
    // Hide the Add Consent button when there are 10 or more items
    addConsentBtn.style.display = "none";
  } else {
    // Show the Add Consent button when there are fewer than 10 items
    addConsentBtn.style.display = "block";
  }
}
