// Function to remove an additional consent link
import checkAdditionalLinksCount from "./checkAdditionalLinksCount";

export default function removeAdditionalLink(link) {
  let additionalLinkContainer = link.closest('.additional-link-container');
  let additionalLinksContainer = additionalLinkContainer.closest('.additional-links-container');
  additionalLinkContainer.remove();
  checkAdditionalLinksCount(additionalLinksContainer);
}
