export default function transportTab() {
  try {
    // Initialize zone toggle functionality
    initializeZoneToggles();

    // Initialize method toggles per zone
    initializeMethodToggles();

    // Initialize option checkboxes for each shipping method
    initializeOptionCheckboxes();

    // Initialize shipping method select change handlers
    initializeShippingMethodHandlers();

    initializeListenerForGroups();
  } catch (error) {
    console.error('Fatal error in transportTab initialization:', error);
    throw new Error('9a0b1c2d-3e4f-5a6b-7c8d-9e0f1a2b3c4d');
  }
}

/**
 * Initialize zone accordion toggles
 */
function initializeZoneToggles() {
  try {
    const zoneHeadings = document.querySelectorAll('#inpostpayadmin .izi-zone-heading');

    if (!zoneHeadings || zoneHeadings.length === 0) {
      console.warn('No zone headings found - UUID: 67d80a45-23f1-4c59-8ba1-c76342e18f9d');
      return;
    }

    zoneHeadings.forEach(heading => {
      const zoneId = heading.dataset.zoneId;
      if (!zoneId) {
        console.warn('Zone heading without zone ID - UUID: a89bc123-45d6-78ef-90ab-cd12ef34gh56');
        return;
      }

      const content = document.getElementById(`zone-content-${zoneId}`);
      if (!content) {
        console.warn(`Zone content not found for zone ${zoneId} - UUID: 78ef90ab-cd12-ef34-gh56-12a3b4c5d6e7`);
        return;
      }

      content.style.overflow = 'hidden';
      content.style.maxHeight = '0';
      content.style.transition = 'max-height 0.3s ease-out';
      content.style.display = 'none';

      heading.addEventListener('click', () => {
        const isVisible = window.getComputedStyle(content).display !== 'none';

        if (isVisible) {
          const contentHeight = content.scrollHeight;

          content.style.maxHeight = contentHeight + 'px';
          content.offsetHeight;
          content.style.maxHeight = '0';

          setTimeout(() => {
            content.style.display = 'none';
          }, 300);

          heading.classList.remove('active');

          const toggleIcon = heading.querySelector('.izi-zone-toggle-icon');
          if (toggleIcon) {
            toggleIcon.classList.remove('active');
          }
        } else {
          content.style.display = 'block';
          content.style.maxHeight = '0';

          content.offsetHeight;

          const contentHeight = content.scrollHeight;
          content.style.maxHeight = contentHeight + 'px';

          setTimeout(() => {
            content.style.maxHeight = 'none';
          }, 300);

          heading.classList.add('active');

          const toggleIcon = heading.querySelector('.izi-zone-toggle-icon');
          if (toggleIcon) {
            toggleIcon.classList.add('active');
          }
        }
      });
    });

    if (zoneHeadings.length > 0) {
      const firstHeading = zoneHeadings[0];
      const firstZoneId = firstHeading.dataset.zoneId;
      const firstContent = document.getElementById(`zone-content-${firstZoneId}`);

      if (firstContent) {
        firstContent.style.display = 'block';
        firstContent.style.maxHeight = 'none';
        firstHeading.classList.add('active');

        const toggleIcon = firstHeading.querySelector('.izi-zone-toggle-icon');
        if (toggleIcon) {
          toggleIcon.classList.add('active');
        }
      }
    }
  } catch (error) {
    console.error('Error initializing zone toggles:', error);
    throw new Error('ab23cd45-ef67-89ab-cdef-12345678abcd');
  }
}

/**
 * Initialize shipping method toggles in each zone
 */
function initializeMethodToggles() {
  try {
    const zoneSections = document.querySelectorAll('#inpostpayadmin .izi-zone-section');

    if (!zoneSections || zoneSections.length === 0) {
      console.warn('No zone sections found - UUID: 56ab78cd-90ef-12gh-34ij-56kl78mn90op');
      return;
    }

    zoneSections.forEach(zoneSection => {
      const zoneId = zoneSection.dataset.zoneId;
      if (!zoneId) {
        console.warn('Zone section without zone ID - UUID: 12gh34ij-56kl-78mn-90op-12qr34st56uv');
        return;
      }

      const courierSwitch = zoneSection.querySelector(`input[id$="izi_group_courier_active_${zoneId}"]`);
      const apmSwitch = zoneSection.querySelector(`input[id$="izi_group_apm_active_${zoneId}"]`);

      const courierSection = zoneSection.querySelector('.izi-courier-section');
      const apmSection = zoneSection.querySelector('.izi-apm-section');

      if (courierSwitch && courierSection) {
        courierSwitch.addEventListener('change', e => {
          toggleSectionVisibility(courierSection, e.target.checked);
          updateNoMethodSelectedWarning(zoneSection);
        });

        toggleSectionVisibility(courierSection, courierSwitch.checked);
      } else {
        console.warn(`Missing courier elements for zone ${zoneId}:`,
          courierSwitch ? 'Switch found' : 'Switch missing',
          courierSection ? 'Section found' : 'Section missing');
      }

      if (apmSwitch && apmSection) {
        apmSwitch.addEventListener('change', e => {
          toggleSectionVisibility(apmSection, e.target.checked);
          updateNoMethodSelectedWarning(zoneSection);
        });

        toggleSectionVisibility(apmSection, apmSwitch.checked);
      } else {
        console.warn(`Missing APM elements for zone ${zoneId}:`,
          apmSwitch ? 'Switch found' : 'Switch missing',
          apmSection ? 'Section found' : 'Section missing');
      }

      updateNoMethodSelectedWarning(zoneSection);
    });
  } catch (error) {
    console.error('Error initializing method toggles:', error);
    throw new Error('34ij56kl-78mn-90op-12qr-34st56uv78wx');
  }
}

/**
 * Initialize option checkboxes for COD and PWW
 */
function initializeOptionCheckboxes() {
  try {
    const zoneSections = document.querySelectorAll('#inpostpayadmin .izi-zone-section');

    if (!zoneSections || zoneSections.length === 0) {
      console.warn('No zone sections found - UUID: 90op12qr-34st-56uv-78wx-90yz12ab34cd');
      return;
    }

    zoneSections.forEach(zoneSection => {
      const zoneId = zoneSection.dataset.zoneId;
      if (!zoneId) {
        console.warn('Zone section without zone ID - UUID: 56uv78wx-90yz-12ab-34cd-56ef78gh90ij');
        return;
      }

      // Find option checkboxes for this zone with zone-specific IDs
      const optionCheckboxes = zoneSection.querySelectorAll(
        `input[id$="_cod_apm_active_${zoneId}"],
         input[id$="_cod_courier_active_${zoneId}"],
         input[id$="_pww_apm_active_${zoneId}"]`
      );

      optionCheckboxes.forEach(checkbox => {
        const transportGroup = checkbox.closest('.izi-transport-group');
        if (!transportGroup) {
          console.warn(`No transport group found for checkbox ${checkbox.id} - UUID: 12ab34cd-56ef-78gh-90ij-12kl34mn56op`);
          return;
        }

        handleOptionToggle(checkbox, transportGroup);

        checkbox.addEventListener('change', () => {
          handleOptionToggle(checkbox, transportGroup);
          // Note: We don't reset select values when checkbox is unchecked to preserve data
        });
      });
    });
  } catch (error) {
    console.error('Error initializing option checkboxes:', error);
    throw new Error('12ab34cd-56ef-78gh-90ij-12kl34mn56op');
  }
}

/**
 * Initialize shipping method select handlers
 */
function initializeShippingMethodHandlers() {
  try {
    const zoneSections = document.querySelectorAll('#inpostpayadmin .izi-zone-section');

    if (!zoneSections || zoneSections.length === 0) {
      console.warn('No zone sections found - UUID: 78gh90ij-12kl-34mn-56op-78qr90st12uv');
      return;
    }

    zoneSections.forEach(zoneSection => {
      const zoneId = zoneSection.dataset.zoneId;
      if (!zoneId) {
        console.warn('Zone section without zone ID - UUID: 34mn56op-78qr-90st-12uv-34wx56yz78ab');
        return;
      }

      const methodSelects = zoneSection.querySelectorAll('select[name*="shipping_method"]');

      methodSelects.forEach(select => {
        const transportGroup = select.closest('.izi-transport-group');

        if (!transportGroup) {
          console.warn(`No transport group found for select ${select.name}`);
          return;
        }

        handleShippingMethodChange(select, transportGroup);

        select.addEventListener('change', () => handleShippingMethodChange(select, transportGroup));
      });
    });
  } catch (error) {
    console.error('Error initializing shipping method handlers:', error);
    throw new Error('90st12uv-34wx-56yz-78ab-90cd12ef34gh');
  }
}

/**
 * Toggle section visibility
 */
function toggleSectionVisibility(section, isActive) {
  try {
    if (!section) {
      throw new Error('c87e9db2-5c03-4fa5-9e02-f2b87aa9ce12');
    }

    section.classList.toggle('izi-section-active', isActive);
    section.classList.toggle('izi-section-inactive', !isActive);
    section.style.display = isActive ? 'block' : 'none';
  } catch (error) {
    console.error('Error toggling section visibility:', error);
    throw new Error('e09c1f8a-51bf-42b1-abc0-1e94d9a6b82d');
  }
}

/**
 * Update the no method selected warning
 */
function updateNoMethodSelectedWarning(zoneSection) {
  try {
    const zoneId = zoneSection.dataset.zoneId;
    if (!zoneId) {
      return;
    }

    const warningElement = zoneSection.querySelector('.izi-no-delivery-method-selected');
    if (!warningElement) {
      console.warn(`Warning element not found for zone ${zoneId}`);
      return;
    }

    const courierSwitch = zoneSection.querySelector(`input[id$="izi_group_courier_active_${zoneId}"]`);
    const apmSwitch = zoneSection.querySelector(`input[id$="izi_group_apm_active_${zoneId}"]`);

    const courierActive = courierSwitch && courierSwitch.checked;
    const apmActive = apmSwitch && apmSwitch.checked;

    const shouldShowWarning = !courierActive && !apmActive;

    warningElement.classList.toggle('izi-section-active', shouldShowWarning);
    warningElement.classList.toggle('izi-section-inactive', !shouldShowWarning);
    warningElement.style.display = shouldShowWarning ? 'block' : 'none';
  } catch (error) {
    console.error('Error updating method warning:', error);
  }
}

function isDefaultValue(select) {
  if (!select) return true;
  const v = select.value;
  const first = select.options[0]?.value ?? '';
  return v === '' || v === '0' || v === first;
}

function getGroupCheckbox(transportGroup) {
  return transportGroup.querySelector('.izi-group-checkbox-wrapper input[type="checkbox"]');
}

function refreshMapping(transportGroup) {
  if (!transportGroup) return;

  const groupCb = getGroupCheckbox(transportGroup);
  const groupOn = !groupCb || groupCb.checked;

  // Get all subgroups within this transport group
  const subgroups = Array.from(transportGroup.querySelectorAll('.izi-group-subgroup'));

  if (!groupOn) {
    // If main checkbox is unchecked, make everything readonly/disabled except the main checkbox
    subgroups.forEach(subgroup => {
      subgroup.querySelectorAll('input[type="text"], input[type="number"], textarea').forEach(el => {
        el.readOnly = true;
      });
      subgroup.querySelectorAll('select').forEach(el => {
        el.disabled = true;
      });
      subgroup.querySelectorAll('input[type="radio"]').forEach(el => {
        el.disabled = true;
      });
    });
    return;
  }

  // Main checkbox is checked, enable radios but handle readonly based on radio selection
  const radios = Array.from(transportGroup.querySelectorAll('.izi-group-subgroup-radio'));
  const radioName = radios[0]?.name;
  const activeRadio = radioName ? transportGroup.querySelector(`.izi-group-subgroup-radio[name="${CSS.escape(radioName)}"]:checked`) : null;

  // Enable all radios
  radios.forEach(r => { r.disabled = false; });

  if (!activeRadio) {
    // No radio selected, make all inputs readonly
    subgroups.forEach(subgroup => {
      subgroup.querySelectorAll('select, input[type="text"], input[type="number"], textarea').forEach(el => {
        el.readOnly = true;
      });
    });
    return;
  }

  // Handle readonly based on selected radio value
  const selectedValue = activeRadio.value;

  subgroups.forEach(subgroup => {
    const subgroupRadios = Array.from(subgroup.querySelectorAll('.izi-group-subgroup-radio'));
    if (subgroupRadios.length === 0) return;

    const hasActiveRadio = subgroupRadios.some(radio => radio === activeRadio);
    if (hasActiveRadio) {
      // This subgroup contains the active radio
      if (selectedValue === 'shipping_method') {
        // Make shipping method selects editable, fee inputs readonly
        subgroup.querySelectorAll('select[name*="shipping_method"]').forEach(el => {
          el.disabled = false;
        });
        subgroup.querySelectorAll('input[name*="shipping_price"], input[type="number"]').forEach(el => {
          el.readOnly = true;
        });
      } else if (selectedValue === 'fee') {
        // Make fee inputs editable, shipping method selects readonly
        subgroup.querySelectorAll('input[name*="shipping_price"], input[type="number"]').forEach(el => {
          el.readOnly = false;
        });
        subgroup.querySelectorAll('select[name*="shipping_method"]').forEach(el => {
          el.disabled = true;
        });
      }
    } else {
      // This subgroup doesn't contain the active radio, make everything readonly
      subgroup.querySelectorAll('select, input[type="text"], input[type="number"], textarea').forEach(el => {
        if (el.type === 'select-one') {
          el.disabled = true;
        } else {
          el.readOnly = true;
        }
      });
    }
  });
}

function handleOptionToggle(checkbox, transportGroup) {
  refreshMapping(transportGroup);
}

function handleShippingMethodChange(select, transportGroup) {
  refreshMapping(transportGroup);
}

function initializeListenerForGroups() {
  document.querySelectorAll('#inpostpayadmin .izi-transport-group').forEach(transportGroup => {
    const groupCheckbox = transportGroup.querySelector('.izi-group-checkbox-wrapper input[type="checkbox"]');
    if (groupCheckbox) groupCheckbox.addEventListener('change', () => refreshMapping(transportGroup));

    transportGroup.querySelectorAll('.izi-group-subgroup-radio').forEach(r => {
      r.addEventListener('change', () => refreshMapping(transportGroup));
    });

    transportGroup.querySelectorAll('select[name^="izi_shipping_method_"]').forEach(s => {
      s.addEventListener('change', () => handleShippingMethodChange(s, transportGroup));
    });

    refreshMapping(transportGroup);
  });
}
