// Function to check the number of consent items and toggle the Add Consent button
export default function checkAdditionalLinksCount(linksContainer) {

  const linkItems = linksContainer.querySelectorAll(".additional-link-container").length;
  const addLinkBtn = linksContainer.parentNode.getElementsByClassName('add-additional-link-btn')[0];

  if (linkItems >= 3) {
    // Hide the Add Additional Link button when there are 3 or more items
    addLinkBtn.style.display = "none";
  } else {
    // Show the Add Additional Link button when there are fewer than 3 items
    addLinkBtn.style.display = "block";
  }
}
